from typing import List

class Solution:
    def minimumIndex(self, nums: List[int]) -> int:
        # Step 1: Find the dominant element
        freq = {}
        for num in nums:
            freq[num] = freq.get(num, 0) + 1

        dominant = None
        for num, count in freq.items():
            if count * 2 > len(nums):
                dominant = num
                break

        # Step 2: Use prefix sum approach to find the minimum valid split index
        prefix = 0
        for i, num in enumerate(nums):
            if num == dominant:
                prefix += 1
            # Check if current split is valid
            if prefix * 2 > (i + 1) and (freq[dominant] - prefix) * 2 > (len(nums) - (i + 1)):
                return i

        return -1
